// This file is automatically generated. Do not edit it directly.
import { createClient } from '@supabase/supabase-js';
import type { Database } from './types';

const SUPABASE_URL = import.meta.env.VITE_SUPABASE_URL;
const SUPABASE_PUBLISHABLE_KEY = import.meta.env.VITE_SUPABASE_PUBLISHABLE_KEY || import.meta.env.VITE_SUPABASE_ANON_KEY;

if (!SUPABASE_URL || !SUPABASE_PUBLISHABLE_KEY) {
  console.error('❌ MISING SUPABASE CONFIGURATION:');
  console.error('VITE_SUPABASE_URL:', SUPABASE_URL);
  console.error('VITE_SUPABASE_PUBLISHABLE_KEY:', SUPABASE_PUBLISHABLE_KEY ? 'Present' : 'Missing');
  console.log('⚠️ Application will likely fail to render.');
}

// Import the supabase client like this:
// import { supabase } from "@/integrations/supabase/client";

// Глобальное in-memory хранилище (сохраняется между перерендерами)
const globalMemoryStorage: Record<string, string> = {};

// Используем localStorage для персистентности сессии между страницами
const getStorageAdapter = () => {
  // Сначала пробуем localStorage - главный способ хранения для web-приложений
  try {
    const testKey = '__supabase_test__';
    window.localStorage.setItem(testKey, 'test');
    window.localStorage.removeItem(testKey);
    console.log('✅ localStorage доступен (используется для сохранения сессии)');
    return window.localStorage;
  } catch (e) {
    console.warn('⚠️ localStorage недоступен:', e);
  }

  // Затем пробуем sessionStorage как fallback
  try {
    const testKey = '__supabase_test__';
    window.sessionStorage.setItem(testKey, 'test');
    window.sessionStorage.removeItem(testKey);
    console.log('✅ sessionStorage доступен (fallback)');
    return window.sessionStorage;
  } catch (e) {
    console.warn('⚠️ sessionStorage недоступен:', e);
  }

  // Fallback: глобальное in-memory storage
  console.warn('⚠️ Используем глобальное in-memory storage (сессия будет потеряна при перезагрузке страницы)');
  return {
    getItem: (key: string) => {
      console.log('📖 memory.getItem:', key, '→', globalMemoryStorage[key]?.substring(0, 50));
      return globalMemoryStorage[key] || null;
    },
    setItem: (key: string, value: string) => {
      console.log('💾 memory.setItem:', key, '→', value.substring(0, 50));
      globalMemoryStorage[key] = value;
    },
    removeItem: (key: string) => {
      console.log('🗑️ memory.removeItem:', key);
      delete globalMemoryStorage[key];
    },
  };
};

export const supabase = createClient<Database>(SUPABASE_URL, SUPABASE_PUBLISHABLE_KEY, {
  auth: {
    storage: getStorageAdapter() as any,
    persistSession: true,
    autoRefreshToken: true,
    detectSessionInUrl: true,
    flowType: 'implicit',
    storageKey: 'sb-auth-token',
    debug: false
  }
});